(13143, 1310, 1, NULL, '(ა) იმ შენობა-ნაგებობათა კლასებს და მშენებლობის სახეებს, რომელიც ექვემდებარება მშენებლობის ნებართვას ან მშენებლობის შეტყობინებას, გარდა V კლასის შენობა-ნაგებობისა, სანებართვო დოკუმენტაციის შემადგენლობას, მათი შედგენისათვის წინასაპროექტო კვლევის ჩატარების წესსა და პირობებს, სანებართვო პირობებს, მათი შესრულების პროცესს, შენობა-ნაგებობის ექსპლუატაციაში მიღებისათვის ვარგისად აღიარების წესსა და პირობებს', '2025-02-21 18:16:11', '2025-02-21 18:16:11'),
(13144, 1310, 0, NULL, '(ბ) იმ შენობა-ნაგებობათა კლასებს და მშენებლობის სახეებს, რომელიც ექვემდებარება მშენებლობის ნებართვას ან მშენებლობის შეტყობინებას, სანებართვო დოკუმენტაციის შემადგენლობას, მათი შედგენისათვის წინასაპროექტო კვლევის ჩატარების წესსა და პირობებს, სანებართვო პირობებს, მათი შესრულების პროცესს, შენობა-ნაგებობის ექსპლუატაციაში მიღებისათვის ვარგისად აღიარების წესსა და პირობებს', '2025-02-21 18:16:11', '2025-02-21 18:16:11'),
(13145, 1310, 0, NULL, '(გ) სამშენებლო და არასამშენებლო ტერიტორიებს, აგრეთვე, მათში დასაშვებ შენობა-ნაგებობის სახეობების ჩამონათვალს, გარდა V კლასის შენობა-ნაგებობისა, სანებართვო დოკუმენტაციის შემადგენლობას და შენობა-ნაგებობის ექსპლუატაციაში მიღებისათვის ვარგისად აღიარების წესსა და პირობებს', '2025-02-21 18:16:11', '2025-02-21 18:16:11');
